<body>
  <div class="page">
    <div class="card">
      <div class="header">
        <h1 class="title">历史结果（列过滤器预览）</h1>
      </div>

      <div class="tableWrap">
        <table>
          <thead>
            <tr>
              <th class="col-model" id="th-model">
                <div class="thRow">
                  <span>模型名称</span>
                  <button class="filterBtn" id="filterBtn" aria-label="filter">
                    <!-- 漏斗/筛选图标 -->
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                      <path d="M4 6h16M7 12h10M10 18h4"
                        stroke="currentColor" stroke-width="2" stroke-linecap="round"/>
                    </svg>
                  </button>
                </div>

                <div class="dropdown" id="dropdown">
                  <div class="label">按“模型名称”包含关键字过滤</div>
                  <input id="filterInput" placeholder="例如：interns1" autocomplete="off" />
                  <div class="btnRow">
                    <button class="btn primary" id="applyBtn">应用</button>
                    <button class="btn" id="resetBtn">重置</button>
                    <button class="btn link" id="closeBtn">关闭</button>
                  </div>
                </div>
              </th>
              <th class="col-ver">数据集版本</th>
              <th class="col-metric">指标</th>
              <th class="col-score">得分</th>
              <th class="col-task">任务详情</th>
            </tr>
          </thead>
          <tbody id="tbody"></tbody>
        </table>
      </div>

      <div class="footer">
        <div>共 <span id="count">0</span> 条</div>
        <div id="activeFilter"></div>
      </div>
    </div>
  </div>

<script>
  const data = [
    { model:"interns1-pro-candidate1-think-nosys-set1-temp0.8", ver:"bb832d", metric:"accuracy (32 runs average)", score:93.65, task:"api_eval_v3_3491" },
    { model:"interns1-pro-candidate6-think-nosys-set1",        ver:"bb832d", metric:"accuracy (32 runs average)", score:93.23, task:"api_eval_v3_3383" },
    { model:"interns1-pro-candidate1-think-nosys",             ver:"bb832d", metric:"accuracy (32 runs average)", score:93.12, task:"api_eval_v3_3548" },
    { model:"interns1-pro-candidate3-think-nosys",             ver:"bb832d", metric:"accuracy (32 runs average)", score:93.12, task:"api_eval_v3_3458" },
    { model:"interns1_mini_enhance_math_20251229rc20",         ver:"bb832d", metric:"accuracy (32 runs average)", score:92.40, task:"api_eval_v3_3658" },
    { model:"other-model-abc-001",                             ver:"aa1111", metric:"accuracy (32 runs average)", score:90.10, task:"api_eval_v3_2001" },
    { model:"baseline-x-large",                                ver:"cc2222", metric:"accuracy (32 runs average)", score:89.44, task:"api_eval_v3_2002" },
  ];

  const tbody = document.getElementById("tbody");
  const countEl = document.getElementById("count");
  const activeFilterEl = document.getElementById("activeFilter");

  const thModel = document.getElementById("th-model");
  const btn = document.getElementById("filterBtn");
  const dropdown = document.getElementById("dropdown");
  const input = document.getElementById("filterInput");
  const applyBtn = document.getElementById("applyBtn");
  const resetBtn = document.getElementById("resetBtn");
  const closeBtn = document.getElementById("closeBtn");

  let filterValue = "";

  function esc(s){
    return String(s).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;")
      .replaceAll('"',"&quot;").replaceAll("'","&#39;");
  }

  function getFiltered(){
    const k = filterValue.trim().toLowerCase();
    if(!k) return data;
    return data.filter(r => String(r.model).toLowerCase().includes(k));
  }

  function render(){
    const rows = getFiltered();
    countEl.textContent = rows.length;

    tbody.innerHTML = rows.map(r => `
      <tr>
        <td title="${esc(r.model)}">${esc(r.model)}</td>
        <td>${esc(r.ver)}</td>
        <td title="${esc(r.metric)}">${esc(r.metric)}</td>
        <td><strong>${esc(r.score)}</strong></td>
        <td><a href="#" onclick="return false;">${esc(r.task)}</a></td>
      </tr>
    `).join("") || `<tr><td colspan="5" style="color:#6b7280;padding:16px;">无匹配结果</td></tr>`;

    btn.classList.toggle("active", !!filterValue);

    if(filterValue){
      activeFilterEl.innerHTML = `
        <span class="pill">
          模型名称：<strong>${esc(filterValue)}</strong>
          <button class="x" id="pillClear" aria-label="clear">×</button>
        </span>
      `;
      document.getElementById("pillClear").onclick = () => {
        filterValue = "";
        input.value = "";
        render();
      };
    }else{
      activeFilterEl.innerHTML = "";
    }
  }

  function openDropdown(){
    dropdown.classList.add("open");
    setTimeout(()=> input.focus(), 0);
  }
  function closeDropdown(){
    dropdown.classList.remove("open");
  }

  btn.addEventListener("click", (e)=>{
    e.stopPropagation();
    dropdown.classList.contains("open") ? closeDropdown() : openDropdown();
  });

  applyBtn.addEventListener("click", ()=>{
    filterValue = input.value;
    render();
    closeDropdown();
  });

  resetBtn.addEventListener("click", ()=>{
    filterValue = "";
    input.value = "";
    render();
  });

  closeBtn.addEventListener("click", closeDropdown);

  input.addEventListener("keydown", (e)=>{
    if(e.key === "Enter"){
      filterValue = input.value;
      render();
      closeDropdown();
    }
    if(e.key === "Escape"){
      closeDropdown();
    }
  });

  // 点击外部关闭
  document.addEventListener("click", (e)=>{
    if(!thModel.contains(e.target)) closeDropdown();
  });

  render();
</script>
</body>
</html>
